import React, { useState, useEffect } from 'react';
import './App.css';

const ws_url = 'ws://localhost:8001/ws';

function App() {
    const [messages, setMessages] = useState([]);
    const [socket, setSocket] = useState(null);
    const [inputMessage, setInputMessage] = useState('');
    const [conversationId, setConversationId] = useState(''); // Store conversation ID

    useEffect(() => {
        // Create a WebSocket connection
        const ws = new WebSocket(`${ws_url}/abc-123`);

        ws.onopen = () => {
            console.log('WebSocket connection established');
        };

        ws.onmessage = (event) => {
            const data = JSON.parse(event.data);
            console.log('Received message:', data);

            // Update conversationId if it's present in the message
            if (data.conversation_id) {
                setConversationId(data.conversation_id);
            }

            // Append received message if it contains content
            if (data.type === 'chunk' && data.content) {
                setMessages(prevMessages => [
                    ...prevMessages, 
                    { content: data.content, id: Date.now() }
                ]);
            }
        };

        ws.onerror = (error) => {
            console.error('WebSocket error:', error);
        };

        ws.onclose = () => {
            console.log('WebSocket connection closed');
        };

        // Store WebSocket connection in state
        setSocket(ws);

        // Cleanup on component unmount
        return () => {
            if (ws) {
                ws.close();
            }
        };
    }, []);

    // Send a message to the WebSocket server
    const sendMessage = () => {
        if (socket && socket.readyState === WebSocket.OPEN) {
            const message = {
                query: inputMessage,
                conversation_id: conversationId, // Use the stored conversation ID
            };

            socket.send(JSON.stringify(message));
            setInputMessage(''); // Clear input after sending
        } else {
            console.error('WebSocket is not open');
        }
    };

    return (
        <div>
            <h1>Chat</h1>
            <ul>
                {messages.map((message, index) => (
                    <li key={index}>{message.content}</li>
                ))}
            </ul>

            <input
                type="text"
                value={inputMessage}
                onChange={(e) => setInputMessage(e.target.value)}
                placeholder="Type a message..."
            />

            <button onClick={sendMessage}>Send Message</button>

            <p>Conversation ID: {conversationId || 'None'}</p> {/* Show conversation ID */}
        </div>
    );
}

export default App;
